_DATA = json.loads(_PAYLOAD)
AS_OF = _DATA["as_of"]                  # ISO date the snapshot was taken
AS_OF_DECIMAL = _DATA["as_of_decimal"]  # same date as a decimal year, for CAGR
STOCKS = _DATA["stocks"]
ORDER = _DATA["order"]                  # display order for the dropdown

CURRENCY_SYMBOL = {"INR": "\u20b9", "USD": "$"}


def catalog():
    """Everything the page needs to build the stock + year dropdowns.

    Returns the snapshot date and a list of stocks in display order, each with
    its name, sector group, currency, the today price and the sorted list of
    year-ends we have a price for.
    """
    out = []
    for sym in ORDER:
        s = STOCKS[sym]
        years = sorted(int(y) for y in s["years"])
        out.append({
            "symbol": sym,
            "name": s["name"],
            "group": s["group"],
            "currency": s["currency"],
            "currency_symbol": CURRENCY_SYMBOL.get(s["currency"], ""),
            "first_year": years[0],
            "last_year": years[-1],
            "years": years,
            "now": s["now"],
        })
    return {"as_of": AS_OF, "stocks": out}


def invest(symbol, amount, year):
    """Grow ``amount`` invested in ``symbol`` at the end of ``year`` to today.

    symbol — a ticker key present in STOCKS (e.g. "RELIANCE.NS")
    amount — lump sum invested, in the stock's currency (INR)
    year   — calendar year whose year-end price is the entry point

    Returns a dict with the entry/now prices, the value today, absolute gain,
    the growth multiple, total return %, years held and the annualised CAGR %.
    Raises KeyError for an unknown symbol and ValueError for a year we have no
    price for (or a non-positive entry price).
    """
    s = STOCKS[symbol]
    ystr = str(int(year))
    if ystr not in s["years"]:
        raise ValueError("no year-end price for %s at %s" % (symbol, ystr))
    start = s["years"][ystr]
    now = s["now"]
    if start <= 0 or now is None:
        raise ValueError("bad price data for %s" % symbol)

    multiple = now / start
    value = amount * multiple

    # Entry is the year-end (~31 Dec of `year`), i.e. ~1 Jan of the next year.
    years_held = AS_OF_DECIMAL - (int(year) + 1.0)
    if years_held <= 0:
        years_held = max(AS_OF_DECIMAL - int(year), 0.01)
    cagr = multiple ** (1.0 / years_held) - 1.0

    return {
        "symbol": symbol,
        "name": s["name"],
        "currency": s["currency"],
        "currency_symbol": CURRENCY_SYMBOL.get(s["currency"], ""),
        "amount": amount,
        "year": int(year),
        "as_of": AS_OF,
        "start_price": start,
        "now_price": now,
        "value": value,
        "gain": value - amount,
        "multiple": multiple,
        "total_return_pct": (multiple - 1.0) * 100.0,
        "years_held": years_held,
        "cagr_pct": cagr * 100.0,
    }


if __name__ == "__main__":
    # Sanity check: a known long holding should multiply many times over.
    cat = catalog()
    assert cat["stocks"], "catalog is empty"
    assert all(s["years"] for s in cat["stocks"]), "a stock has no years"

    r = invest("RELIANCE.NS", 100000, 2000)
    assert r["value"] > 100000, r
    assert r["multiple"] > 1, r
    assert r["years_held"] > 20, r

    # round-trip: value == amount * multiple, gain consistent
    assert abs(r["value"] - r["amount"] * r["multiple"]) < 1e-6
    assert abs(r["gain"] - (r["value"] - r["amount"])) < 1e-6

    # unknown ticker / year raise
    for bad in [lambda: invest("NOPE", 1, 2000),
                lambda: invest("RELIANCE.NS", 1, 1850)]:
        try:
            bad(); raise AssertionError("expected an error")
        except (KeyError, ValueError):
            pass

    print("AS_OF", AS_OF, "| stocks:", len(cat["stocks"]))
    print("Rs.1,00,000 in Reliance at end-2000 -> Rs.{:,.0f} today "
          "({:.1f}x, {:.1f}%/yr)".format(
              r["value"], r["multiple"], r["cagr_pct"]))
